('Delivery', 'Retirada no Balcão', 'Mesa', 0, 0, 274, '259', NULL, '', 'Zaria', 0, 'Zaria produz sandálias artesanais e camisas personalizadas que preservam a cultura e histórias de Serra Pelada, unindo estilo, conforto e memória local.', '26', '14', '5572', 'zaria', '274/2026/01/1315220126gjagcgdhj9.jpg', '274/2026/01/1322220126i05ffedjkg.jpg', '#373737', 10.00, '1', '1', 'Visa, Mastercard e Elo', '1', 'Visa, Mastercard e Elo', '2', '', '2', 'Cheque, transferência e permuta', '1', '68523-000', 's\\n', 'SERENO', 'R SERENO', 'B Serra Pelada', '', 'S\\HF', '1', '', '', 0.00, '(94) 98138-5360', 'franzreis.fran@gmail.com', '', '', '', '', '', '', 'FRANCISCA ZACARIAS REIS', '03/02/1984', '2', '18145533000127', 'franzreis.fran2@gmail.com', '2026-01-22 12:20:09', '2026-01-22 13:28:44', '2026-01-22 12:20:09', '1', '2', '1', '1', '1', '1', 2, '365', '2', NULL, '999', '1', NULL, '73915351253', 'CPF', '1', '1', '1', '2', '', NULL, NULL, NULL, 2, NULL, NULL, NULL, NULL, 2, 0, '', '', 2, 0, '', '', 2, NULL, 2, 0, '', '', '', 2),
('Entrega pelo 99 motos', 'Retirada no Balcão', '', 0, 0, 277, '261', NULL, '', 'Karina Saboaria', 0, 'Fitocosméticos Naturais, elaborados artesanalmente com plantas, óleos e manteigas vegetais amazônicas, óleos essenciais e ingredientes suaves e não poluentes. A linha sólida além de ser prática para o uso do dia a dia, transporte e armazenamento, não contém embalagem poluente, são armazenados em celulose e papel, todos compostáveis. \r\nA maioria dos produtos são feitos sob encomenda, depois de uma conversa sobre o couro cabeludo, a pele e os fios. Cada ser é único e tem suas necessidades individuais, então o produto é pensado e elaborado a partir disso.\r\n\r\nKarina Saboaria acredita que tudo que precisamos está aqui, na superfície da Terra, nas plantas, nas águas... Que não somos superiores à nada e que não temos o direito de poluir o habitat de todos em detrimento de nosso ego e vaidade.', '34', '14', '5571', 'karinasaboaria', '277/2026/02/1750110226hf9aebebk8.png', '277/2026/02/1750110226kjibeefci2.png', '#016253', 30.00, '1', '2', '', '1', 'Visa, Mastercard e Elo', NULL, NULL, NULL, NULL, '1', '68515-000', '187', 'Bairro Primavera', 'Rua Marcos Freire, ', 'AP. 02', '', 'Segunda: 9h  às 17h\r\n\r\nTerça: 9h às 17h\r\n\r\nQuarta: 9h às 17h\r\n\r\nQuinta: 9h às 17h\r\n\r\nSexta: 9h às 17h\r\n\r\nSábado: fechado \r\n\r\nDomingo: fechado', '1', '', '', 0.00, '(94) 99903-4411', 'karinasaboaria@gmail.com', 'https://www.instagram.com/karinasaboaria', '', 'https://share.google/jtFQkkPlnYhBRkKvf', '', '', '', 'Karina Martins de Carvalho ', '28/07/1979', '1', '04448498662', 'karinasaboaria@gmail.com', '2026-02-11 16:32:51', '2026-02-13 19:21:07', '2026-02-11 16:32:51', '1', '2', '1', '1', '1', '1', 2, '364', '2', NULL, '999', '1', NULL, 'karinasaboaria@gmailcom', 'E-mail', '1', '1', '1', '1', '', NULL, NULL, NULL, 2, NULL, NULL, NULL, NULL, 2, 0, '', '', 2, 0, '', '', 2, NULL, 2, 0, '', '', '', 1),
