('Entrega', 'Retirada na loja', '', 0, 0, 279, '263', NULL, '', 'Gurgueia Delicias da Amazônia', 0, 'A Gurgueia Indústria de Alimentos é uma microindústria amazônica fundada em 2016, sediada em Parauapebas, especializada na produção artesanal de licores, geleias, doces, balas e bombons à base de frutos regionais como cupuaçu e açaí.', '35', '14', '2506', 'gurgueia', '279/2026/02/2017190226j67kgg1icf.png', '279/2026/02/20331902260ab7fcb4f1.png', '#007e57', 10.00, '1', '2', '', '', '', NULL, NULL, NULL, NULL, '1', '68515-000', '2', 'BAIRRO RIO VERDE', 'Av. Rio Grande', 'Portão verde, prédio', 'Em frente ao posto de gasolina', 'Todos os dias', '1', '', '', 0.00, '(94) 99285-1262', 'Gurgueia22@gmail.com', 'https://www.instagram.com/gurgueia_delicias_da_amazonia/', '', '', '', '', '', 'Nubia Gugueia Bizerra', '13/04/1981', '1', '90858352249', 'Gurgueia22@gmail.com', '2026-02-13 18:27:06', '2026-02-23 15:30:45', '2026-02-13 18:27:06', '1', '2', '1', '1', '1', '1', 2, '363', '2', NULL, '999', '1', NULL, '03807203370', 'CPF', '1', '1', '', '', '', NULL, NULL, NULL, 2, NULL, NULL, NULL, NULL, 2, 0, '', '', 0, 0, '', '', 2, NULL, 0, 0, '', '', '', 2),
