('Delivery', 'Retirada no Balcão', '', 0, 0, 282, '266', NULL, '', 'JPB', 0, 'Trabalho com bordados artesanais personalizados, criando peças exclusivas em roupas, quadros decorativos e itens de cama, mesa e banho. Cada detalhe é cuidadosamente bordado à mão, com dedicação, sensibilidade e acabamento de alta qualidade.\r\n\r\nTambém desenvolvo poesias transformadas em arte têxtil — histórias contadas em versos e eternizadas em bordado, criando peças únicas, afetivas e cheias de significado.\r\n\r\nOfereço atendimento atencioso, personalizado e focado na melhor experiência para cada cliente. Agradeço pela confiança e por escolher valorizar o feito à mão.', '26', '14', '5572', 'jbp', '282/2026/02/1724200226kafag98hjg.png', '282/2026/02/1725200226fiadakeeii.png', '#d0b58d', 25.00, '1', '1', 'Visa, Mastercard e Elo', '', '', NULL, NULL, NULL, NULL, '1', '68523-000', '15', 'telepará', 'dilson funario', 'Serra Pelada', 'O ateliê é em local Residêncial.', 'segunda: das 08:00 as 11:00; das 13:00 às 17:00\r\nTerça: das 08:00 as 11:00; das 13:00 às 17:00\r\nQuarta: das 08:00 as 11:00; das 13:00 às 17:00\r\nQuinta: das 08:00 as 11:00; das 13:00 às 17:00\r\nSexta: das 08:00 as 11:00; das 13:00 às 17:00\r\nSabado: das 08:00 as 11:00; das 13:00 às 17:00\r\nDomingo: das 08:00 as 11:00; das 13:00 às 17:00', '1', '', '', 0.00, '(94) 98143-5287', 'josianapaz25@gmail.com', '@josi_poetiza', '@Josiana severo', '', '', '', '', 'josiana severo da paz silva', '06/06/1978', '1', '00822126192', 'josianapaz25@gmail.com', '2026-02-20 16:57:14', '2026-02-25 18:16:19', '2026-02-20 16:57:14', '1', '2', '1', '1', '1', '1', 2, '365', '2', NULL, '999', '1', NULL, '(94)981435287', 'Celular', '1', '1', '', '', '', NULL, NULL, NULL, 2, NULL, NULL, NULL, NULL, 2, 0, '', '', 0, 0, '', '', 2, NULL, 0, 0, '', '', '', 2),
('Delivery, 99 Entregas', 'Retirada no Balcão', '', 0, 0, 283, '267', NULL, '', 'Ateliê MM', 0, 'Atuo com bordados artesanais feitos à mão, incluindo bordado livre, ponto cruz e vagonite. Produzo peças personalizadas e exclusivas para roupas, enxovais de cama, mesa e banho, além de quadros decorativos e outros trabalhos artesanais.\r\n\r\nCada criação é desenvolvida com cuidado nos detalhes, acabamento de qualidade e atenção especial ao que o cliente deseja, transformando linhas e tecidos em peças únicas e cheias de significado.', '26', '14', '5572', 'ateliemm', '283/2026/03/1751040326cbai3bj3ch.png', '283/2026/03/17510403265hk6gij1ie.png', '#446fc4', 20.00, '1', '2', '', '', '', NULL, NULL, NULL, NULL, '1', '68523-000', '40', 'Sereno', 'Travessa Amapá', '', '', '', '1', '', '', 0.00, '(94) 99901-2596', 'a991509511@gmail.com', '', '', '', '', '', '', 'Maria Martins de Moraes', '25/10/1973', '1', '63496976268', 'a991509511@gmail.com', '2026-02-20 17:40:14', '2026-03-04 18:06:54', '2026-02-20 17:40:14', '1', '2', '1', '1', '1', '1', 2, '365', '2', NULL, '999', '1', NULL, 'a991509511@gmailcom', 'E-mail', '1', '1', '', '', '', NULL, NULL, NULL, 2, NULL, NULL, NULL, NULL, 2, 0, '', '', 0, 0, '', '', 2, NULL, 0, 0, '', '', '', 2),
('Delivery', 'Retirada no Balcão', '', 0, 0, 285, '269', NULL, '', 'Ateliê Maria Antonia', 0, 'Sou bordadeira profissional dedicada à criação de peças estilizadas, marcadas por cores intensas e composições que celebram a beleza viva da natureza. Transformo inspirações naturais em arte têxtil, explorando contrastes, texturas e profundidade para dar vida a flores exuberantes, folhagens delicadas e elementos orgânicos cheios de personalidade', '26', '14', '5572', 'atelimariaantonia', '285/2026/02/2157230226ehd5j28gdk.png', '285/2026/03/1925020326dejb1ed7aa.png', '#007e5e', 30.00, '1', '1', 'Visa, Mastercard e Elo', '', '', NULL, NULL, NULL, NULL, '1', '58523-000', '104', 'Sereno', 'travessa curió', '', '', '', '1', '', '', 0.00, '(94) 99233-8854', 'Toniapontes123@gmail.com', '', '', '', '', '', '', 'Maria Antônia Furtado Pontes', '20/08/1967', '1', '39549801349', 'Toniapontes123@gmail.com', '2026-02-23 21:39:48', '2026-03-02 19:28:48', '2026-02-23 21:39:48', '1', '2', '1', '1', '1', '1', 2, '365', '2', NULL, '999', '1', NULL, '00032551444', 'CPF', '1', '1', '', '', '', NULL, NULL, NULL, 2, NULL, NULL, NULL, NULL, 2, 0, '', '', 0, 0, '', '', 2, NULL, 0, 0, '', '', '', 2),
('Delivery', 'Retirada no Balcão', '', 0, 0, 286, '270', NULL, '', 'Bordadeira de Serra Pelada', 0, 'Sou bordadeira especializada em peças exclusivas que transformam o simples em extraordinário. Produzo quadros bordados que decoram e encantam, batas personalizadas com identidade única, saquinhos delicados, capas de almofada cheias de personalidade, bolsas e ecobags que unem estilo e sustentabilidade, além de chaveiros e ímãs criativos que carregam charme em cada ponto.', '26', '14', '2459', 'bordadeiradeserrapelada', '286/2026/03/184502032654jjdiie0c.png', '286/2026/03/1845020326df0behjgbc.png', '#fa8096', 25.00, '1', '1', 'Visa, Mastercard e Elo', '', '', NULL, NULL, NULL, NULL, '1', '68923-000', '0', 'Bairro Centro', 'Rua Principal', 'Curionópolis', '', 'De domingo a domingo nos seguintes horarios: \r\nDas 08h00 ás 11h00 e das 13h00 ás 14hs\r\n ', '1', '', '', 0.00, '(94) 99199-8912', '', '', '', '', '', '', '', 'Rosangela Carvalho Vieira', '22/07/1979', '1', '02406399362', 'rosangelacarvalhovieira@gmail.com', '2026-02-23 22:13:17', '2026-03-02 18:45:32', '2026-02-23 22:13:17', '1', '2', '1', '1', '1', '1', 2, '365', '2', NULL, '999', '1', NULL, '02406399362', 'CPF', '1', '1', '', '', '', NULL, NULL, NULL, 2, NULL, NULL, NULL, NULL, 2, 0, '', '', 0, 0, '', '', 2, NULL, 0, 0, '', '', '', 2),
