(861, '147', '128', '147/2023/03/00451303231ef7ajicak.jpg', 'REF-861', NULL, 0, 0, 0, 'Creatina Monohidratada Double Force Pote 150g - Body Action', '', 'CREATINA DOUBLE FORCE é um suplemento a base de Creatina Monohidratada, Isomaltulose (Palatinose), Glicina e Biotina: uma potente e exclusiva combinação que promove maior eficácia e absorção da creatina, além de agir no aumento da força, visando apoiar seus resultados nas atividades físicas.\r\n\r\nCREA-ATP\r\nA Creatina auxilia no aumento do desempenho físico durante exercícios repetidos de curta duração e alta intensidade. A fórmula com Glicina potencializa a ação da creatina.', 59.99, '1', 54.99, 'null', '1', '1', '2023-03-13 00:45:00', '2023-03-13 00:45:00', '1', '1', NULL, NULL, NULL, NULL, NULL, '1', '0', NULL, NULL, NULL, NULL, NULL),
