(872, '147', '145', '/2023/03/0909130323k3cha5d7ga.jpg', 'REF-872', NULL, 0, 0, 0, '4 X Cafeina Fullife 210mg 120 Caps', '', 'FullFlame é um suplemento de cafeína Anidra,o que garante índices extremos de estimulação. Seu corpo passa a ter uma elevada carga de energia, aprimorando o foco e a concentração. Acelera dramaticamente o metabolismo das gorduras, favorecendo a redução do peso corporal e poupando o glicogênio, retardando assim a fadiga muscular.\r\nA cafeína aumenta a concentração e foco para as atividades realizadas no dia a dia.\r\n\r\nBenefícios:\r\nEstimulante de disposição física e mental;\r\nAumento de concentração, força, disposição e resistência;\r\nAuxilia e eleva a termogênese;\r\nPromove a produção de energia por meio da utilização da gordura corporal.\r\nSugestão de uso:\r\nIngerir 2 cápsula ao dia de preferência antes do treino.', 49.99, '2', 49.99, 'null', '1', '1', '2023-03-13 09:09:33', '2023-03-13 09:09:33', '1', '1', NULL, NULL, NULL, NULL, NULL, '1', '0', NULL, NULL, NULL, NULL, NULL),
(873, '147', '336', '/2023/03/0913130323iffjibbgch.jpg', 'REF-873', NULL, 0, 0, 0, 'Colágeno Bodyaction  200g', '', 'COLÁGENO HIDROLISADO CT-1 NUTRI SCIENTE® - BODYACTION\r\nConheça o novo Colágeno CT-1 Nutri Science em pó da Bodyaction. Com 9G de peptídeos de colágeno por dose, ele é 100% Hidrolisado e fornece as proteínas e vitaminas necessárias para melhora da saúde dos cabelos, unhas e pele, além de prevenir o aparecimento de estrias e marcas de expressão. Contém as Vitaminas C, E, A, Zinco e Selênio. Experimente o poder do Novo Colágeno Bodyaction Nutri Science.\r\n________________', 59.99, '2', 59.99, 'null', '1', '1', '2023-03-13 09:13:11', '2023-03-13 09:13:11', '1', '1', NULL, NULL, NULL, NULL, NULL, '1', '0', NULL, NULL, NULL, NULL, NULL),
(874, '147', '337', '147/2023/03/09211303231ciggd6k7b.jpg', 'REF-874', NULL, 0, 0, 0, 'Coqueteleira Probiótica', '', 'A coqueteleira da Probiótica vai proporcionar mais praticidade no preparo dos seus suplementos alimentares, além de garantir a dosagem exata e ser muito prática de higienizar.\r\nAlém disso a coqueteleira possui uma tela interna móvel que garante um shake mais cremoso e homogêneo.\r\nEm material atóxico e resistente.', 19.99, '2', 19.99, 'null', '1', '1', '2023-03-13 09:21:21', '2023-03-13 09:21:21', '1', '1', NULL, NULL, NULL, NULL, NULL, '1', '0', NULL, NULL, NULL, NULL, NULL),
