(1084, '233', '383', '233/2025/07/1728020725jge1bkjaeh.jpg', 'REF-1084', NULL, 0, 0, 0, 'UVA', '', 'Suco encorpado, naturalmente doce e aromático. Feito com uvas frescas, ganha apenas um leve toque de açúcar para realçar sua intensidade frutada. Sabor marcante, cor vibrante e uma sensação de frescor a cada gole – perfeito para quem aprecia um clássico cheio de personalidade.', 0.00, '2', 0.00, '[\n    {\n        \"nome\": \"VEFNQU5IT1M=\",\n        \"escolha_minima\": \"MQ==\",\n        \"escolha_maxima\": \"MTA=\",\n        \"item\": [\n            {\n                \"nome\": \"S2lkcyAyMDBtbA==\",\n                \"descricao\": \"\",\n                \"valor\": \"NC41MA==\"\n            },\n            {\n                \"nome\": \"MzAwbWw=\",\n                \"descricao\": \"\",\n                \"valor\": \"NS45OQ==\"\n            },\n            {\n                \"nome\": \"MSBMaXRybw==\",\n                \"descricao\": \"\",\n                \"valor\": \"MTQuOTk=\"\n            }\n        ]\n    }\n]', '1', '1', '2025-07-02 17:28:54', '2025-07-15 10:05:24', '1', '1', NULL, NULL, NULL, NULL, NULL, '1', '0', NULL, 0, 0, 0, 0.000),
