(1135, '235', '411', '235/2025/07/08581407259eefgh4ij8.jpeg', 'REF-1135', NULL, 0, 0, 0, 'ESPALIT DUO C/ 20 COMP.', '', 'Espaslit Duo é um medicamento indicado para tratamento dos sintomas de cólicas, dores e desconforto na barriga - Promove o alívio rápido e prolongado das cólicas, dores e desconforto na barriga .', 48.00, '2', 48.00, '[\n    {\n        \"nome\": \"\",\n        \"escolha_minima\": \"MQ==\",\n        \"escolha_maxima\": \"Ng==\"\n    }\n]', '1', '1', '2025-07-14 08:58:15', '2025-07-14 08:58:15', '1', '1', NULL, NULL, NULL, NULL, NULL, '2', '6', NULL, 0, 0, 0, 0.000),
(1136, '235', '411', '235/2025/07/0905140725ejefhfj7eh.jpeg', 'REF-1136', NULL, 0, 0, 0, 'NEOCOPAN', '', 'Neocopan Composto® tem ação antiespasmódica, agindo sobre as contrações dolorosas e aliviando de forma rápida e prolongada as cólicas, dores e desconfortos abdominais.', 25.00, '1', 0.00, '[\n    {\n        \"nome\": \"\",\n        \"escolha_minima\": \"MQ==\",\n        \"escolha_maxima\": \"MTA=\",\n        \"item\": [\n            {\n                \"nome\": \"TkVPQ09QQU4gQ09NUC4gQy8gMjAgQ09NUC4=\",\n                \"descricao\": \"QU5USUVTUEFTTU9ESUNP\",\n                \"valor\": \"MTkuOTk=\"\n            },\n            {\n                \"nome\": \"TkVPQ09QQU4gR09UQVMgMTBNTA==\",\n                \"descricao\": \"QU5USUVTUEFTTU9JRElDTw==\",\n                \"valor\": \"MTkuOTk=\"\n            }\n        ]\n    }\n]', '1', '1', '2025-07-14 09:05:25', '2025-07-14 09:05:25', '1', '1', NULL, NULL, NULL, NULL, NULL, '2', '12', NULL, 0, 0, 0, 0.000),
