(1138, '235', '389', '235/2025/07/0942140725bb2509h1kd.jpeg', 'REF-1138', NULL, 0, 0, 0, 'PARACETAMOL 750MG C/ 20 COMP.', '', 'Paracetamol 750mg é utilizado para tratamento da febre e de dores leves a moderadas como dores associadas a resfriados, dores de cabeça, dor de dente, dor nas costas, dores musculares, cólicas menstruais e dores associadas a artrite.', 14.35, '1', 9.99, '[\n    {\n        \"nome\": \"\",\n        \"escolha_minima\": \"MQ==\",\n        \"escolha_maxima\": \"MTA=\"\n    }\n]', '1', '1', '2025-07-14 09:42:18', '2025-07-14 09:42:18', '1', '1', NULL, NULL, NULL, NULL, NULL, '2', '12', NULL, 0, 0, 0, 0.000),
