(1424, '235', '401', '235/2025/08/1053130825ikc82fbjid.jpeg', 'REF-1424', NULL, 0, 0, 0, 'SABONETE LÍQUIDO GLICERINADO GRANADO 250ML ', '', 'O sabonete líquido glicerinado para bebê é especialmente desenvolvido para a pele delicada do bebê, limpando com suavidade e deixando-a macia e perfumada por mais tempo. Formulado com pH da pele e glicerina vegetal pura, que auxilia na hidratação, ajudando a evitar possíveis alergias.', 29.99, '2', 29.99, 'null', '1', '1', '2025-08-13 10:53:22', '2025-08-13 10:53:22', '1', '1', NULL, NULL, NULL, NULL, NULL, '2', '01', NULL, 0, 0, 0, 0.000),
