(1900, '284', '592', '284/2026/02/1952240226eh1kdb5cde.png', 'REF-1900', NULL, 0, 0, 0, 'Brincando de Florescer', '', '“Brincando de Florescer” é uma tela bordada à mão que celebra o ciclo da vida e a delicadeza do florescer. A composição combina elementos florais estilizados, cores vibrantes e texturas cuidadosamente trabalhadas, criando uma cena cheia de energia e sensibilidade artística.', 250.00, '2', 250.00, 'null', '1', '1', '2026-02-24 19:52:06', '2026-02-24 19:59:00', '1', '1', NULL, NULL, NULL, NULL, NULL, '1', '1', NULL, 0, 0, 0, 0.000),
