(1902, '284', '592', '284/2026/02/2021240226kc5cj6iege.png', 'REF-1902', NULL, 0, 0, 0, 'Bordado de Flores', '', 'Este bordado de flores é uma peça artesanal criada à mão, onde cores, formas e texturas se unem para transmitir leveza e harmonia. As pétalas ganham volume através dos pontos cuidadosamente aplicados, enquanto folhas e ramos trazem movimento e naturalidade à composição.', 0.00, '2', 0.00, 'null', '1', '1', '2026-02-24 20:21:19', '2026-02-24 20:21:19', '1', '1', NULL, NULL, NULL, NULL, NULL, '1', '1', NULL, 0, 0, 0, 0.000),
(1903, '282', '593', '282/2026/02/2121240226jebcff6b0h.png', 'REF-1903', NULL, 0, 0, 0, 'Bolsa Pequena - Tico Tico', '', 'A bolsa pequena Tico-Tico traz um bordado artesanal feito ponto a ponto, retratando a ave com riqueza de detalhes, cores harmoniosas e traços que valorizam sua delicadeza. O desenho ganha vida através das linhas cuidadosamente aplicadas, criando textura, profundidade e personalidade.', 50.00, '2', 50.00, 'null', '1', '1', '2026-02-24 21:07:18', '2026-02-24 21:21:41', '1', '1', NULL, NULL, NULL, NULL, NULL, '1', '1', NULL, 0, 0, 0, 0.000),
(1904, '282', '594', '282/2026/02/21242402260bh6kbhbaa.png', 'REF-1904', NULL, 0, 0, 0, 'História dos Garimpeiros', '', 'Historia do local onde os garimpeiros trabalham', 30.00, '2', 30.00, 'null', '1', '1', '2026-02-24 21:24:02', '2026-02-24 21:31:22', '1', '1', NULL, NULL, NULL, NULL, NULL, '1', '1', NULL, 0, 0, 0, 0.000),
(1905, '282', '593', '282/2026/02/2126240226j0hec1ehgi.png', 'REF-1905', NULL, 0, 0, 0, 'Ecobag Passaro Tico-Tico', '', 'A Ecobag Pássaro Tico-Tico é bordada à mão com atenção minuciosa aos detalhes, retratando a delicadeza e o charme dessa ave tão presente na natureza brasileira. O bordado valoriza as cores, o contorno e a expressão do pássaro, criando uma composição harmoniosa e cheia de vida.', 170.00, '2', 170.00, 'null', '1', '1', '2026-02-24 21:26:24', '2026-02-24 21:26:24', '1', '1', NULL, NULL, NULL, NULL, NULL, '1', '1', NULL, 0, 0, 0, 0.000),
(1906, '282', '593', '282/2026/02/2131240226hkfaka47fg.png', 'REF-1906', NULL, 0, 0, 0, 'Quadro Tangará', '', 'Este quadro bordado à mão retrata o Tangará com toda a sua elegância e intensidade de cores, destacando o contraste vibrante entre o corpo escuro e os detalhes marcantes que dão identidade à ave. Cada ponto é cuidadosamente aplicado para criar textura, profundidade e realismo, valorizando a expressividade do pássaro em seu habitat.\r\nTamanho: Médio', 350.00, '2', 350.00, 'null', '1', '1', '2026-02-24 21:31:05', '2026-02-24 21:31:05', '1', '1', NULL, NULL, NULL, NULL, NULL, '1', '1', NULL, 0, 0, 0, 0.000),
