(1987, '283', '610', '283/2026/03/1701040326dbfefiki2j.png', 'REF-1987', NULL, 0, 0, 0, 'Alofada 3 Garimpeiros - Bordado a Mão', '', 'A Almofada 3 Garimpeiros é uma peça artesanal única, com bordado feito à mão que retrata de forma detalhada a cena tradicional dos garimpeiros. Produzida com cuidado e dedicação, ela traz um toque rústico e cultural à decoração, valorizando o trabalho manual e a arte regional. Ideal para decorar salas, quartos ou ambientes especiais, unindo conforto, história e autenticidade em uma peça exclusiva.', 300.00, '2', 300.00, 'null', '1', '1', '2026-03-04 17:01:04', '2026-03-04 17:01:04', '1', '1', NULL, NULL, NULL, NULL, NULL, '1', '1', NULL, 40, 0, 40, 0.000),
(1988, '283', '611', '283/2026/03/1703040326fd91j9dicj.png', 'REF-1988', NULL, 0, 0, 0, 'Saquinho 1 Garimpeiro - Bordado a Mão', '', 'O Saquinho 1 Garimpeiro é uma peça artesanal delicada, com bordado feito à mão que retrata o tradicional garimpeiro com riqueza de detalhes. Produzido com carinho e capricho, ele une arte, cultura e utilidade em um único item. Ideal para guardar pequenos objetos, lembranças ou presentear alguém especial. Uma peça exclusiva que valoriza o trabalho manual e a tradição do bordado artesanal.', 100.00, '2', 100.00, 'null', '1', '1', '2026-03-04 17:03:10', '2026-03-04 17:03:10', '1', '1', NULL, NULL, NULL, NULL, NULL, '1', '1', NULL, 31, 0, 22, 0.000),
(1989, '283', '610', '283/2026/03/17040403263fhbe5kdcj.png', 'REF-1989', NULL, 0, 0, 0, 'Saquinho Açai  - Bordado a Mão', '', 'O Saquinho Açaí é uma peça artesanal encantadora, com bordado feito à mão que representa o tradicional fruto amazônico. Produzido com cuidado e riqueza de detalhes, ele valoriza a cultura regional e o trabalho manual. Ideal para guardar pequenos objetos, lembranças ou presentear alguém especial. Uma peça delicada que une arte, tradição e utilidade.', 80.00, '2', 80.00, 'null', '1', '1', '2026-03-04 17:04:48', '2026-03-04 17:04:48', '1', '1', NULL, NULL, NULL, NULL, NULL, '1', '1', NULL, 31, 0, 22, 0.000),
